test_that("rank_wt computes weighted midpoint ranks", {
  expect_equal(
    rank_wt(c(10, 20, 30), c(1, 1, 2)),
    c(0.125, 0.375, 0.75)
  )
})

test_that("rank_wt returns ranks in the order of retained inputs", {
  expect_equal(
    rank_wt(c(20, 10, 30), c(1, 1, 2)),
    c(0.375, 0.125, 0.75)
  )
})

test_that("rank_wt drops missing and non-positive weights before ranking", {
  expect_equal(
    rank_wt(c(2, NA, 1, 3), c(1, 1, 0, 2)),
    c(1 / 6, 2 / 3)
  )
})

test_that("rank_wt handles edge cases", {
  expect_equal(rank_wt(5, 2), 0.5)
  expect_equal(rank_wt(c(1, 2), c(0, NA)), numeric(0))
  expect_error(rank_wt(1:2, 1))
})

test_that("rank_wt assigns one weighted midpoint to tied rank blocks", {
  expect_equal(
    rank_wt(c(10, 20, 20, 40), rep(1, 4)),
    c(0.125, 0.5, 0.5, 0.875)
  )
  expect_equal(
    rank_wt(c(10, 20, 20, 40), c(1, 2, 3, 4)),
    c(0.05, 0.35, 0.35, 0.8)
  )
})

test_that("rank_wt tied ranks are stable under row reordering", {
  expected <- c(0.35, 0.8, 0.35, 0.05)

  expect_equal(
    rank_wt(c(20, 40, 20, 10), c(3, 4, 2, 1)),
    expected
  )
  expect_equal(
    rank_wt(c(20, 40, 20, 10), c(2, 4, 3, 1)),
    expected
  )
})

test_that("ci_factory returns scoring functions and validates type", {
  expect_true(is.function(ci_factory("CI")))
  expect_true(is.function(ci_factory("CIg")))
  expect_true(is.function(ci_factory("CIc")))
  expect_true(is.function(ci_factory("L")))
  expect_error(ci_factory("bad"))
})

test_that("ci_factory computes direct CI variants on a simple example", {
  y <- cbind(c(10, 20, 30), c(1, 0, 1))
  wt <- c(1, 1, 2)

  ci <- ci_factory("CI")
  cig <- ci_factory("CIg")
  cic <- ci_factory("CIc")

  expect_equal(ci(y, wt), 1 / 12)
  expect_equal(cig(y, wt), 0.0625)
  expect_equal(cic(y, wt), 0.25)
})

test_that("ci_factory matches direct weighted-covariance reference calculations", {
  y <- cbind(
    rank = c(4, 1, 3, 2, 5),
    outcome = c(0, 1, 3, 2, 5)
  )
  wt <- c(1, 2, 1, 3, 2)

  reference_score <- function(y, wt, type) {
    ok <- stats::complete.cases(y) & !is.na(wt) & wt > 0
    y <- y[ok, , drop = FALSE]
    wt <- wt[ok]
    y[, 1] <- rank_wt(y[, 1], wt)
    wt_norm <- wt / sum(wt)
    mean_rank <- sum(wt_norm * y[, 1])
    mean_outcome <- sum(wt_norm * y[, 2])
    cov12 <- sum(wt_norm * (y[, 1] - mean_rank) * (y[, 2] - mean_outcome))

    if (type == "CI") {
      return(abs(2 * cov12 / mean_outcome))
    }
    if (type == "CIg") {
      return(abs(2 * cov12))
    }
    4 * abs(2 * cov12) / (max(y[, 2]) - min(y[, 2]))
  }

  expect_equal(ci_factory("CI")(y, wt), reference_score(y, wt, "CI"))
  expect_equal(ci_factory("CIg")(y, wt), reference_score(y, wt, "CIg"))
  expect_equal(ci_factory("CIc")(y, wt), reference_score(y, wt, "CIc"))
})

test_that("ci_factory drops incomplete and non-positive-weight rows", {
  y1 <- cbind(c(10, 20, 30, NA), c(1, 0, 1, 1))
  wt1 <- c(1, 1, 2, 1)

  y2 <- cbind(c(10, 20, 30), c(1, 0, 1))
  wt2 <- c(1, 1, 2)

  ci <- ci_factory("CI")
  expect_equal(ci(y1, wt1), ci(y2, wt2))

  y3 <- cbind(c(10, 20, 30, 40), c(1, 0, 1, 1))
  wt3 <- c(1, 1, 2, 0)
  expect_equal(ci(y3, wt3), ci(y2, wt2))
})

test_that("ci_factory returns zero for insufficient valid data", {
  ci <- ci_factory("CI")
  y <- cbind(c(10, NA), c(1, 0))
  wt <- c(1, 1)

  expect_equal(ci(y, wt), 0)
})

test_that("ci_factory handles degenerate denominators", {
  ci <- ci_factory("CI")
  cic <- ci_factory("CIc")

  y_mu0 <- cbind(c(10, 20, 30), c(0, 0, 0))
  expect_equal(ci(y_mu0, c(1, 1, 1)), 0)

  y_rng0 <- cbind(c(10, 20, 30), c(5, 5, 5))
  expect_equal(cic(y_rng0, c(1, 1, 1)), 0)
})

test_that("ci_factory is invariant to rescaling weights", {
  y <- cbind(c(10, 20, 30), c(1, 0, 1))
  ci <- ci_factory("CI")

  expect_equal(ci(y, c(1, 1, 2)), ci(y, c(10, 10, 20)))
})

test_that("ci_factory rank-dependent scores are stable within tied ranks", {
  y <- cbind(
    rank = c(10, 20, 20, 40, 40, 50),
    outcome = c(0, 1, 0, 1, 0, 1)
  )
  wt <- c(1, 2, 4, 3, 1, 2)
  permutation <- c(1, 3, 2, 5, 4, 6)

  for (type in c("CI", "CIg", "CIc")) {
    ci <- ci_factory(type)
    expect_equal(
      ci(y, wt),
      ci(y[permutation, , drop = FALSE], wt[permutation])
    )
  }
})

test_that("ci_factory L computes level-dependent bivariate index", {
  y <- cbind(
    ses = c(1, 2, 3),
    outcome = c(0, 1, 1)
  )
  wt <- c(1, 1, 1)

  expect_equal(ci_factory("L")(y, wt), 1 / 6)
