test_that("L index is zero when outcome is constant", {
  y <- cbind(
    ses = c(1, 2, 3, 4),
    outcome = c(1, 1, 1, 1)
  )
  wt <- rep(1, 4)

  expect_equal(ci_factory("L")(y, wt), 0)
})

test_that("L index is invariant to positive rescaling of SES", {
  y1 <- cbind(
    ses = c(1, 2, 3, 4),
    outcome = c(0, 1, 0, 1)
  )
  y2 <- cbind(
    ses = 10 * y1[, "ses"],
    outcome = y1[, "outcome"]
  )
  wt <- rep(1, 4)

  expect_equal(ci_factory("L")(y1, wt), ci_factory("L")(y2, wt))
})

test_that("L index warns once per session for negative socioeconomic levels", {
  warning_state <- getFromNamespace(".ci_warning_state", "ineqTrees")
  warning_state$negative_l <- FALSE
  on.exit(warning_state$negative_l <- FALSE, add = TRUE)

  y <- cbind(
    ses = c(-1, 1, 2),
    outcome = c(0, 1, 1)
  )
  wt <- rep(1, 3)
  l_index <- ci_factory("L")

  expect_warning(
    l_index(y, wt),
    "negative values"
  )
  expect_warning(
    l_index(y, wt),
    NA
  )
  expect_warning(
    ci_factory("L")(y, wt),
    NA
  )
  expect_warning(
    ci_factory("CI")(y, wt),
    NA
  )
})

test_that("weighted_ci_gain computes parent minus weighted child impurity", {
  y <- cbind(ses = 1:4, health = c(10, 20, 30, 40))
  wt <- c(1, 2, 3, 4)
  left <- c(TRUE, TRUE, FALSE, FALSE)
  mock_ci_fun <- function(y, wt) sum(y[, 2] * wt)

  expect_equal(
    weighted_ci_gain(y, wt, left, mock_ci_fun),
    110
  )
})

test_that(".weighted_ci_gain_from_parent matches weighted_ci_gain", {
  y <- cbind(
    ses = c(10, 20, 30, 40, 50),
    health = c(1, 0, 1, 0, 1)
  )
  wt <- c(1, 2, 1, 2, 1)
  left <- c(TRUE, TRUE, FALSE, FALSE, FALSE)
  ci <- ci_factory("CI")
  cached_gain <- getFromNamespace(".weighted_ci_gain_from_parent", "ineqTrees")

  expect_equal(
    cached_gain(
      y = y,
      wt = wt,
      left = left,
      ci_fun = ci,
      ci_parent = ci(y, wt)
    ),
    weighted_ci_gain(y, wt, left, ci)
  )
})

